#include<algorithm>

#include<stdio.h>



using namespace std;

#define INF 1e15

#define MAX_V 100000



typedef struct{

    int to;

    int cost;

} edge;



typedef struct{

    long dist;

    int v;

} rte;



bool operator< (const rte a, const rte b){

    return a.dist > b.dist;  // ascend

}



vector<edge> G[MAX_V];



long d[MAX_V];



void dijkstra(int s, int t);



int main(){



    ios::sync_with_stdio(false);

    cin.tie(nullptr);



    int N, M;

    cin >> N >> M;



    int L[M], R[M], C[M];

    for(int i = 0; i < M; i++){

        cin >> L[i] >> R[i] >> C[i] ;

        L[i]--; R[i]--; 

    }



    int cnt = 0;



    bool bonded[N]; fill(bonded, bonded + N, false);

    for(int i = 0; i<M; i++){

        G[L[i]].emplace_back(edge{R[i], C[i]});

    }



    for(int i = 0; i<N-1; i++){

        G[i+1].emplace_back(edge{i, 0});

    }



    dijkstra(0, N);



    if(d[N-1] == INF) cout << -1 << endl;

    else cout << d[N-1] << endl;



    return 0;



}



void dijkstra(int s, int V){



    fill(d, d + V, INF);



    priority_queue< rte > que;

    d[s] = 0;

    que.push(rte{d[s], s});



    while(!que.empty()){

        rte now = que.top(); que.pop();

        if(now.dist > d[now.v]) continue;

        for(edge e : G[now.v]){

            if(d[e.to] > d[now.v] + e.cost){

                d[e.to] = d[now.v] + e.cost;

                que.push(rte{d[e.to], e.to});

            }



        }

    }

}

