{

//	freopen("input.txt","r",stdin);

	ios::sync_with_stdio(false);

	cin.tie(0);

	cout.tie(0);



	int n,k;

	cin>>n>>k;

	int a,b;

	for(int i=0;i<n;i++)

	{

		cin>>a>>b;

		if(a>k) continue;//要有这个条件，不然下面的vector可能会成负值

		ve[k-a+1].push_back(b);//表示只能在m-a+1天或者之前做

	}

	priority_queue<int> q;

	int earn=0;

	for(int i=k;i>=1;i--)

	{

		for(int v:ve[i]) q.push(v);

		if(!q.empty())

		{

			earn+=q.top();

			q.pop();

		}

	}

	cout<<earn;





	return 0;

 }

