class UnionFind {

  vector<ll> par, rank; // par > 0: number, par < 0: -par

public:

  void init(ll n) {

    par.resize(n, 1); rank.resize(n, 0);

  }

  ll getSize(ll x) {

    return par[find(x)];

  }

  ll find(ll x) {

    if (par[x] > 0) return x;

    return -(par[x] = -find(-par[x]));

  }

  void merge(ll x, ll y) {

    x = find(x);

    y = find(y);

    if (x == y) return;

    if (rank[x] < rank[y]) {

      par[y] += par[x];

      par[x] = -y;

    } else {

      par[x] += par[y];

      par[y] = -x;

      if (rank[x] == rank[y]) rank[x]++;

    }

  }

  bool isSame(ll x, ll y) {

    return find(x) == find(y);

  }

};



template <typename T>

struct UnionFindT {

  vector<ll> par;

  vector<ll> rank;

  vector<T> diff_weight;



  UnionFindT(ll n = 1, T SUM_UNITY = 0) {

    init(n, SUM_UNITY);

  }



  void init(ll n = 1, T SUM_UNITY = 0) {

    par.resize(n); rank.resize(n); diff_weight.resize(n);

    for (ll i = 0; i < n; ++i) par[i] = i, rank[i] = 0, diff_weight[i] = SUM_UNITY;

  }



  ll find(ll x) {

    if (par[x] == x) {

      return x;

    }

    else {

      ll r = find(par[x]);

        diff_weight[x] += diff_weight[par[x]];

        return par[x] = r;

    }

  }



  T weight(ll x) {

    find(x);

    return diff_weight[x];

  }



  bool isSame(ll x, ll y) {

    return find(x) == find(y);

  }



  bool merge(ll x, ll y, T w) {

    w += weight(x); w -= weight(y);

    x = find(x); y = find(y);

    if (x == y) return false;

    if (rank[x] < rank[y]) swap(x, y), w = -w;

    if (rank[x] == rank[y]) ++rank[x];

    par[y] = x;

    diff_weight[y] = w;

    return true;

  }



  T diff(ll x, ll y) {

    return weight(y) - weight(x);

  }

};



class PersistentUnionFind {

  vector<ll> rank, fin, par;

  ll index;

public:

  void init(ll n) {

    index = 0;

    par.resize(n); rank.resize(n, 1); fin.resize(n, 0);

    for (ll i = 0; i < n; i++) par[i] = i;

  }

  ll find(ll x, ll t) {

    if (t >= fin[x] && par[x] != x) return find(par[x], t);

    return x;

  }

  void merge(ll x, ll y) {

    x = find(x, index);

    y = find(y, index);

    index++;

    if (x == y) return;

    if (rank[x] < rank[y]) par[x] = y, fin[x] = index;

    else {

      par[y] = x, fin[y] = index;

      if (rank[x] == rank[y]) rank[x]++;

    }

  }

  bool isSame(ll x, ll y, ll t) { return find(x, t) == find(y, t); }

};



