ll p, a[3000], b[3000];



int main() {

  scanf("%lld", &p);

  for (ll i = 0; i < p; i++) scanf("%lld", &a[i]);

  b[0] = a[0];

  ll inv = invmod(p-1, p);

  for (ll i = 0; i < p; i++) a[i] = (a[i] - b[0] + p) % p;

  for (ll i = p-1; i > 0; i--) {

    for (ll j = 1; j < p; j++) b[i] += a[j];

    b[i] = b[i] * inv % p;

    for (ll j = 1; j < p; j++) a[j] = a[j] * j % p;

  }

  for (ll i = 0; i < p; i++) printf("%lld%c", b[i], i==p-1 ? '\n' : ' ');

}
